import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { 
  Plus, Trash2, Edit, ArrowLeft, X, Save, 
  Loader2, Search, CheckCircle2, Box, Send, Clock, Weight, Upload, ImageIcon
} from 'lucide-react';

import GestionInventario from './GestionInventario'; 
import { generarNombreImagen } from '../utils/helpers';

// COMPONENTE INTERNO: Cargador de imágenes independiente
const CargadorMasivo = ({ onClose, cloudName, folder, preset }) => {
  const [archivos, setArchivos] = useState([]);
  const [subiendo, setSubiendo] = useState(false);
  const [progreso, setProgreso] = useState({});

  const handleFileChange = (e) => {
    setArchivos([...e.target.files]);
  };

  const subirImagenes = async () => {
    setSubiendo(true);
    const resultados = {};

    for (const file of archivos) {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('upload_preset', preset);
      formData.append('folder', folder);
      
      try {
        await axios.post(
          `https://api.cloudinary.com/v1_1/${cloudName}/image/upload`,
          formData
        );
        resultados[file.name] = 'success';
      } catch (err) {
        console.error("Error en:", file.name, err);
        resultados[file.name] = 'error';
      }
      setProgreso({ ...resultados });
    }
    setSubiendo(false);
    alert("Proceso de carga finalizado");
  };

  return (
    <div style={modalOverlay}>
      <div style={{...modalContent, width: '400px'}}>
        <div style={modalHeader}>
          <h3>Cargar Fotos a Cloudinary</h3>
          <button onClick={onClose} style={closeBtn}><X /></button>
        </div>
        <p style={{fontSize: '0.8rem', color: '#64748b', marginBottom: '15px'}}>
          Las imágenes se guardarán con su nombre de archivo (sin códigos extra).
        </p>
        <input type="file" multiple accept="image/*" onChange={handleFileChange} id="file-upload-bulk" style={{display:'none'}} />
        <label htmlFor="file-upload-bulk" style={dropzoneStyle}>
          <ImageIcon size={24} /> 
          <span>{archivos.length > 0 ? `${archivos.length} seleccionadas` : 'Elegir fotos'}</span>
        </label>
        <div style={listStyleScroll}>
          {archivos.map(f => (
            <div key={f.name} style={itemStyleList}>
              <span style={{fontSize:'0.75rem'}}>{f.name}</span>
              {progreso[f.name] === 'success' && <CheckCircle2 color="#10b981" size={14}/>}
              {progreso[f.name] === 'error' && <X color="#ef4444" size={14}/>}
            </div>
          ))}
        </div>
        <button onClick={subirImagenes} disabled={subiendo || archivos.length === 0} style={btnSave}>
          {subiendo ? <Loader2 className="animate-spin" size={18} /> : <Upload size={18} />}
          {subiendo ? 'Subiendo...' : 'Iniciar Carga'}
        </button>
      </div>
    </div>
  );
};

// COMPONENTE PRINCIPAL
const GestionOfertas = () => {
  const { id: localId } = useParams();
  const navigate = useNavigate();
  const [ofertas, setOfertas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showManual, setShowManual] = useState(false);
  const [showCargador, setShowCargador] = useState(false);
  const [editandoProd, setEditandoProd] = useState(null); 
  const [searchTerm, setSearchTerm] = useState("");
  const [publishing, setPublishing] = useState(false);
  const [fechasPublicacion, setFechasPublicacion] = useState({ inicio: '', fin: '' });

  const CLOUD_NAME = "dwpgncjgn";
  const CARPETA = "Inicio/PRODUCTOS";
  const PRESET_NAME = "PRODUCTOS"; // Tu preset Unsigned

  const [nuevoProd, setNuevoProd] = useState({
    tipo: '', marca: '', contenido: '', categoria: 'Almacén',
    precioNuevo: '', precioViejo: '', stock: '', peso: ''
  });

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  const cargarOfertas = useCallback(async () => {
    if (!localId) return;
    setLoading(true);
    try {
      const res = await axios.get(`${API_URL}/api/ofertas/local/${localId}`);
      setOfertas(res.data);
    } catch (e) { console.error(e); } finally { setLoading(false); }
  }, [localId, API_URL]);

  useEffect(() => { cargarOfertas(); }, [cargarOfertas]);

  const handleActualizar = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`${API_URL}/api/ofertas/${editandoProd._id}`, editandoProd);
      setEditandoProd(null);
      cargarOfertas();
    } catch (err) { alert("Error al actualizar"); }
  };

  const handleCargaManual = async (e) => {
    e.preventDefault();
    try {
      const item = {
        ...nuevoProd,
        producto: `${nuevoProd.tipo} ${nuevoProd.marca} ${nuevoProd.contenido}`.trim(),
        publicId: generarNombreImagen(nuevoProd.tipo, nuevoProd.marca, nuevoProd.contenido),
        local: localId,
        precioNuevo: Number(nuevoProd.precioNuevo),
        precioViejo: Number(nuevoProd.precioViejo) || Number(nuevoProd.precioNuevo),
        stock: Number(nuevoProd.stock) || 0,
        peso: Number(nuevoProd.peso) || 0,
        publicado: false
      };
      await axios.post(`${API_URL}/api/ofertas`, item);
      setShowManual(false);
      setNuevoProd({ tipo: '', marca: '', contenido: '', categoria: 'Almacén', precioNuevo: '', precioViejo: '', stock: '', peso: '' });
      cargarOfertas();
    } catch (err) { alert("Error al guardar"); }
  };

  const handlePublicarTodoBorradores = async () => {
    if (!fechasPublicacion.inicio || !fechasPublicacion.fin) return alert("Selecciona fechas.");
    setPublishing(true);
    try {
      await axios.put(`${API_URL}/api/ofertas/publicar-todo/${localId}`, {
        fechaInicio: fechasPublicacion.inicio,
        fechaFin: fechasPublicacion.fin
      });
      setFechasPublicacion({ inicio: '', fin: '' });
      cargarOfertas();
    } catch (err) { alert("Error"); } finally { setPublishing(false); }
  };

  const ofertasFiltradas = useMemo(() => {
    return ofertas.filter(o => o.producto.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [ofertas, searchTerm]);

  const stats = useMemo(() => ({
    total: ofertas.length,
    pendientes: ofertas.filter(o => !o.publicado).length,
    publicadas: ofertas.filter(o => o.publicado).length
  }), [ofertas]);

  return (
    <div style={containerStyle}>
      <div style={topBar}>
        <button onClick={() => navigate('/dashboard')} style={btnBack}><ArrowLeft size={18}/> Volver</button>
        <div style={badgeLocal}>ID Local: {localId?.slice(-6)}</div>
      </div>

      <div style={headerStyle}>
        <div>
          <h1 style={titleStyle}>Panel de Inventario</h1>
          <p style={subtitleStyle}>Control de envíos: Máximo 15kg</p>
        </div>
        <div style={{display:'flex', gap: '10px'}}>
          <button onClick={() => setShowCargador(true)} style={btnCloud}><Upload size={18}/> Cargar Fotos</button>
          <button onClick={() => setShowManual(true)} style={btnPlus}><Plus size={20}/> Nuevo Manual</button>
        </div>
      </div>

      <div style={statsGrid}>
        <div style={statCard}><Box color="#3b82f6" /><div><span style={statNum}>{stats.total}</span><p style={statLabel}>Total</p></div></div>
        <div style={{...statCard, borderLeft: '4px solid #f59e0b'}}><Clock color="#f59e0b" /><div><span style={statNum}>{stats.pendientes}</span><p style={statLabel}>Borradores</p></div></div>
        <div style={{...statCard, borderLeft: '4px solid #10b981'}}><CheckCircle2 color="#10b981" /><div><span style={statNum}>{stats.publicadas}</span><p style={statLabel}>Online</p></div></div>
      </div>

      <GestionInventario localId={localId} onComplete={cargarOfertas} />

      {stats.pendientes > 0 && (
        <div style={publishBannerStyle}>
          <div style={publishInfo}>
            <div style={pendingCountBadge}>{stats.pendientes} borradores</div>
            <div style={dateInputGroup}><label style={dateLabel}>Desde:</label><input type="date" style={dateInput} value={fechasPublicacion.inicio} onChange={e => setFechasPublicacion({...fechasPublicacion, inicio: e.target.value})} /></div>
            <div style={dateInputGroup}><label style={dateLabel}>Hasta:</label><input type="date" style={dateInput} value={fechasPublicacion.fin} onChange={e => setFechasPublicacion({...fechasPublicacion, fin: e.target.value})} /></div>
          </div>
          <button style={btnPublicarMaster} onClick={handlePublicarTodoBorradores} disabled={publishing}>
             {publishing ? <Loader2 className="animate-spin" size={18}/> : <Send size={18}/>} Publicar Lote
          </button>
        </div>
      )}

      <div style={searchBarContainer}>
        <Search size={20} color="#94a3b8" style={searchIcon} />
        <input style={searchInput} placeholder="Buscar en listado..." onChange={e => setSearchTerm(e.target.value)} />
      </div>

      <div style={gridStyle}>
        {loading ? <div style={{textAlign:'center', gridColumn:'1/-1'}}><Loader2 className="animate-spin" size={40}/></div> : ofertasFiltradas.map(o => (
          <div key={o._id} style={{...itemCard, border: o.publicado ? '1px solid #d1fae5' : '1px solid #f1f5f9'}}>
            
            <div style={imageContainerStyle}>
              <img 
                src={`https://res.cloudinary.com/${CLOUD_NAME}/image/upload/f_auto,q_auto/v1/${CARPETA}/${o.publicId}`} 
                alt={o.producto}
                style={imageStyle}
                onError={(e) => { e.target.src = 'https://via.placeholder.com/150/f1f5f9/64748b?text=Sin+Imagen'; }}
              />
            </div>

            <div style={cardHeader}>
              <div style={o.publicado ? badgePublicado : badgeBorrador}>{o.publicado ? 'PUBLICADO' : 'BORRADOR'}</div>
              <div style={{...badgeStockIn, color: o.peso > 15 ? 'red' : '#64748b'}}>
                <Weight size={12} style={{marginRight:4}}/> {o.peso}kg
              </div>
            </div>
            <h4 style={prodName}>{o.producto}</h4>
            <div style={priceContainer}><span style={currentPrice}>${o.precioNuevo}</span><span style={badgeStockIn}>Stock: {o.stock}</span></div>
            <div style={cardFooter}>
              <button style={btnActionEdit} onClick={() => setEditandoProd(o)}><Edit size={16}/> Editar</button>
              <button style={btnActionDelete} onClick={async () => {
                if(window.confirm("¿Eliminar?")) { await axios.delete(`${API_URL}/api/ofertas/${o._id}`); cargarOfertas(); }
              }}><Trash2 size={16}/></button>
            </div>
          </div>
        ))}
      </div>

      {editandoProd && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}><h3>Editar Producto</h3><button onClick={() => setEditandoProd(null)} style={closeBtn}><X/></button></div>
            <form onSubmit={handleActualizar} style={formStyle}>
              
              {/* CAMPO PARA CORREGIR EL PUBLIC ID */}
              <div style={inputGroup}>
                <label style={labelS}>ID de Imagen (Cloudinary)</label>
                <input style={{...inputS, background:'#f0f9ff'}} value={editandoProd.publicId} onChange={e => setEditandoProd({...editandoProd, publicId: e.target.value})} />
                <p style={{fontSize:'0.6rem', color:'#0369a1'}}>Copia el nombre del archivo si no se carga la imagen.</p>
              </div>

              <div style={inputGroup}>
                <label style={labelS}>Nombre del Producto</label>
                <input style={inputS} value={editandoProd.producto} onChange={e => setEditandoProd({...editandoProd, producto: e.target.value})} />
              </div>
              <div style={inputRow}>
                <div style={inputGroup}><label style={labelS}>Precio ($)</label><input style={inputS} type="number" value={editandoProd.precioNuevo} onChange={e => setEditandoProd({...editandoProd, precioNuevo: e.target.value})} /></div>
                <div style={inputGroup}><label style={labelS}>Peso (kg)</label><input style={inputS} type="number" value={editandoProd.peso} onChange={e => setEditandoProd({...editandoProd, peso: e.target.value})} /></div>
              </div>
              <div style={inputRow}>
                <div style={inputGroup}><label style={labelS}>Stock</label><input style={inputS} type="number" value={editandoProd.stock} onChange={e => setEditandoProd({...editandoProd, stock: e.target.value})} /></div>
                <div style={inputGroup}><label style={labelS}>Categoría</label>
                  <select style={inputS} value={editandoProd.categoria} onChange={e => setEditandoProd({...editandoProd, categoria: e.target.value})}>
                    <option>Almacén</option><option>Bebidas</option><option>Limpieza</option><option>Lácteos</option>
                  </select>
                </div>
              </div>
              <button type="submit" style={btnSave}><Save size={18}/> Guardar Cambios</button>
            </form>
          </div>
        </div>
      )}

      {showManual && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}><h3>Nuevo Producto</h3><button onClick={() => setShowManual(false)} style={closeBtn}><X/></button></div>
            <form onSubmit={handleCargaManual} style={formStyle}>
              <div style={inputRow}>
                <div style={inputGroup}><label style={labelS}>Tipo</label><input style={inputS} placeholder="Ej: Aceite" onChange={e => setNuevoProd({...nuevoProd, tipo: e.target.value})} required /></div>
                <div style={inputGroup}><label style={labelS}>Marca</label><input style={inputS} placeholder="Ej: Natura" onChange={e => setNuevoProd({...nuevoProd, marca: e.target.value})} required /></div>
              </div>
              <div style={inputRow}>
                <div style={inputGroup}><label style={labelS}>Contenido</label><input style={inputS} placeholder="Ej: 900ml" onChange={e => setNuevoProd({...nuevoProd, contenido: e.target.value})} required /></div>
                <div style={inputGroup}><label style={labelS}>Peso (kg)</label><input style={inputS} type="number" step="0.01" placeholder="0.9" onChange={e => setNuevoProd({...nuevoProd, peso: e.target.value})} required /></div>
              </div>
              <div style={inputRow}>
                <div style={inputGroup}><label style={labelS}>Precio</label><input style={inputS} type="number" onChange={e => setNuevoProd({...nuevoProd, precioNuevo: e.target.value})} required /></div>
                <div style={inputGroup}><label style={labelS}>Stock</label><input style={inputS} type="number" onChange={e => setNuevoProd({...nuevoProd, stock: e.target.value})} required /></div>
              </div>
              <button type="submit" style={btnSave}><Save size={18}/> Crear Borrador</button>
            </form>
          </div>
        </div>
      )}

      {/* MODAL CARGADOR MASIVO */}
      {showCargador && (
        <CargadorMasivo 
          cloudName={CLOUD_NAME} 
          folder={CARPETA} 
          preset={PRESET_NAME} 
          onClose={() => setShowCargador(false)} 
        />
      )}
    </div>
  );
};

// ESTILOS EXTRA PARA EL CARGADOR
const dropzoneStyle = { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '10px', padding: '20px', border: '2px dashed #e2e8f0', borderRadius: '15px', cursor: 'pointer', background: '#f8fafc' };
const listStyleScroll = { marginTop: '15px', maxHeight: '120px', overflowY: 'auto' };
const itemStyleList = { display: 'flex', justifyContent: 'space-between', padding: '5px 0', borderBottom: '1px solid #f1f5f9' };
const btnCloud = { background: '#8b5cf6', color: 'white', border: 'none', padding: '12px 20px', borderRadius: '12px', fontWeight: '700', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };

// Resto de los estilos (se mantienen igual que los tuyos)
const containerStyle = { padding: '40px', maxWidth: '1200px', margin: '0 auto', fontFamily: '"Inter", sans-serif' };
const topBar = { display: 'flex', justifyContent: 'space-between', marginBottom: '20px' };
const badgeLocal = { background: '#f1f5f9', padding: '6px 15px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: '700' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const titleStyle = { fontSize: '2rem', fontWeight: '900', margin: 0 };
const subtitleStyle = { color: '#64748b' };
const statsGrid = { display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '20px', marginBottom: '30px' };
const statCard = { background: 'white', padding: '20px', borderRadius: '15px', display: 'flex', alignItems: 'center', gap: '15px', border: '1px solid #f1f5f9' };
const statNum = { fontSize: '1.5rem', fontWeight: '900', display: 'block' };
const statLabel = { margin: 0, fontSize: '0.8rem', color: '#64748b' };
const publishBannerStyle = { background: '#0f172a', color: 'white', padding: '20px', borderRadius: '20px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const publishInfo = { display: 'flex', alignItems: 'center', gap: '20px' };
const pendingCountBadge = { background: '#f59e0b', padding: '5px 10px', borderRadius: '8px', fontSize: '0.8rem', fontWeight: '800' };
const dateInputGroup = { display: 'flex', flexDirection: 'column', gap: '4px' };
const dateLabel = { fontSize: '0.65rem', color: '#94a3b8' };
const dateInput = { background: '#1e293b', border: '1px solid #334155', color: 'white', padding: '6px', borderRadius: '8px' };
const btnPublicarMaster = { background: '#10b981', color: 'white', border: 'none', padding: '12px 25px', borderRadius: '12px', fontWeight: '800', cursor: 'pointer', display:'flex', alignItems:'center', gap:8 };
const searchBarContainer = { position: 'relative', marginBottom: '30px' };
const searchIcon = { position: 'absolute', left: '15px', top: '50%', transform: 'translateY(-50%)' };
const searchInput = { width: '100%', padding: '15px 15px 15px 45px', borderRadius: '12px', border: '1px solid #e2e8f0', outline: 'none' };
const gridStyle = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '20px' };
const itemCard = { background: 'white', borderRadius: '20px', padding: '20px', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' };
const imageContainerStyle = { width: '100%', height: '160px', borderRadius: '12px', overflow: 'hidden', marginBottom: '15px', background: '#f8fafc', display: 'flex', justifyContent: 'center', alignItems: 'center' };
const imageStyle = { width: '100%', height: '100%', objectFit: 'contain' };
const cardHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '15px' };
const badgePublicado = { background: '#d1fae5', color: '#065f46', padding: '4px 8px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: '800' };
const badgeBorrador = { background: '#f1f5f9', color: '#64748b', padding: '4px 8px', borderRadius: '6px', fontSize: '0.7rem', fontWeight: '800' };
const badgeStockIn = { fontSize: '0.7rem', color: '#64748b', fontWeight: '600', display:'flex', alignItems:'center' };
const prodName = { margin: '0 0 5px 0', fontSize: '1.1rem', fontWeight: '800' };
const priceContainer = { display: 'flex', justifyContent:'space-between', alignItems: 'baseline' };
const currentPrice = { fontSize: '1.4rem', fontWeight: '900' };
const cardFooter = { display: 'flex', gap: '10px', marginTop: '20px', paddingTop: '15px', borderTop: '1px solid #f1f5f9' };
const btnActionEdit = { flex: 1, background: '#f8fafc', border: 'none', padding: '8px', borderRadius: '8px', cursor: 'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:5 };
